1	import { useMutation } from '@tanstack/react-query';
2	import { useState } from 'react';
3	import { useNavigate } from 'react-router-dom';
4	import { FileUpload } from '@/shared/components/FileUpload/FileUpload';
5	import { Button } from '@/shared/components/ui/button';
6	import { uploadCsv } from './importApi';
7	import { IMPORT_TYPE_HEADER_GUIDES, IMPORT_TYPE_OPTIONS } from './import.model';
8	
9	const fileStatusId = 'import-upload-file-status';
10	const errorStatusId = 'import-upload-error-status';
11	const headerGuideId = 'import-upload-header-guide';
12	
13	export const UploadPage = () => {
14	    const navigate = useNavigate();
15	    const [type, setType] = useState('word');
16	    const [file, setFile] = useState(null);
17	    const [error, setError] = useState('');
18	
19	    const mutation = useMutation({
20	        mutationFn: ({ nextType, nextFile }) => uploadCsv(nextType, nextFile),
21	        onSuccess: ({ historyId }) => {
22	            const nextHistoryId = Number(historyId);
23	
24	            if (!Number.isFinite(nextHistoryId) || nextHistoryId <= 0) {
25	                setError('업로드 응답이 올바르지 않습니다.');
26	                return;
27	            }
28	
29	            navigate(`/import/${nextHistoryId}`);
30	        },
31	    });
32	
33	    const submit = () => {
34	        if (!file) {
35	            setError('CSV 파일을 선택해 주세요.');
36	            return;
37	        }
38	
39	        setError('');
40	        mutation.mutate({ nextType: type, nextFile: file });
41	    };
42	
43	    const describedBy = [file ? fileStatusId : null, error || mutation.isError ? errorStatusId : null]
44	        .filter(Boolean)
45	        .join(' ');
46	
47	    return (
48	        <section className='space-y-5 rounded-2xl border border-border bg-card p-8 text-card-foreground shadow-sm'>
49	            <h1 className='sr-only'>데이터 가져오기 업로드</h1>
50	            <header className='space-y-2'>
51	                <h2 className='text-2xl font-semibold text-card-foreground'>데이터 가져오기</h2>
52	                <p className='text-sm text-muted-foreground'>
53	                    선택한 유형에 맞는 공통 표준 CSV를 업로드합니다. 헤더는 아래 설명에 맞게 준비해 주세요.
54	                </p>
55	            </header>
56	
57	            <fieldset className='space-y-3' aria-describedby={headerGuideId}>
58	                <legend className='text-sm font-medium text-foreground'>가져올 유형 선택</legend>
59	                <div className='flex flex-wrap gap-3'>
60	                    {IMPORT_TYPE_OPTIONS.map((option) => (
61	                        <label
62	                            key={option.value}
63	                            className='inline-flex items-center gap-2 rounded-full border border-slate-300 px-4 py-2 text-sm'
64	                        >
65	                            <input
66	                                type='radio'
67	                                name='importType'
68	                                checked={type === option.value}
69	                                onChange={() => setType(option.value)}
70	                            />
71	                            <span>{option.label}</span>
72	                        </label>
73	                    ))}
74	                </div>
75	                <p id={headerGuideId} aria-live='polite' className='text-sm leading-6 text-muted-foreground'>
76	                    {IMPORT_TYPE_HEADER_GUIDES[type]}
77	                </p>
78	            </fieldset>
79	
80	            <FileUpload
81	                accept='.csv'
82	                maxSizeMB={50}
83	                label='CSV 파일 선택'
84	                onFileSelected={(nextFile) => {
85	                    setFile(nextFile);
86	                    setError('');
87	                }}
88	                onFileRejected={() => {
89	                    setFile(null);
90	                }}
91	            />
92	
93	            {file ? (
94	                <p id={fileStatusId} className='text-sm text-muted-foreground'>
95	                    선택한 파일: {file.name}
96	                </p>
97	            ) : null}
98	            {error ? (
99	                <p id={errorStatusId} role='alert' className='text-sm text-rose-600'>
100	                    {error}
101	                </p>
102	            ) : mutation.isError ? (
103	                <p id={errorStatusId} role='alert' className='text-sm text-rose-600'>
104	                    업로드에 실패했습니다.
105	                </p>
106	            ) : null}
107	
108	            <div className='flex justify-end'>
109	                <Button type='button' aria-describedby={describedBy || undefined} onClick={submit} disabled={mutation.isPending}>
110	                    {mutation.isPending ? '업로드 중...' : '업로드'}
111	                </Button>
112	            </div>
113	        </section>
114	    );
115	};
