1	import { useQuery } from '@tanstack/react-query';
2	import { useState } from 'react';
3	import { Navigate, useParams } from 'react-router-dom';
4	import { DataGrid } from '@/shared/components/DataGrid/DataGrid';
5	import { DetailPanel } from '@/shared/components/DetailPanel/DetailPanel';
6	import {
7	    DetailFields,
8	    DetailHero,
9	    DetailSection,
10	    DetailStat,
11	} from '@/shared/components/DetailView/DetailView';
12	import { getErrorPage, getSummary } from './importApi';
13	import { TERMINAL_STATUSES } from './import.model';
14	
15	const POLL_INTERVAL_MS = 2000;
16	
17	const errorColumns = Object.freeze([
18	    { key: 'rowNo', header: '행 번호', sortable: true, width: 100 },
19	    { key: 'errorCode', header: '오류 코드', sortable: true, width: 200 },
20	    { key: 'errorMessage', header: '오류 메시지', sortable: false },
21	]);
22	
23	const DetailPageContent = ({ historyId }) => {
24	    const numericHistoryId = Number(historyId);
25	    const [sort, setSort] = useState('row_no,asc');
26	    const [page, setPage] = useState(1);
27	    const [size, setSize] = useState(20);
28	    const [detailOpen, setDetailOpen] = useState(false);
29	    const [selectedRawRow, setSelectedRawRow] = useState('');
30	
31	    const summaryQuery = useQuery({
32	        queryKey: ['import-summary', numericHistoryId],
33	        queryFn: () => getSummary(numericHistoryId),
34	        refetchInterval: (query) => {
35	            const status = query.state.data?.history?.status;
36	
37	            if (!status) {
38	                return false;
39	            }
40	
41	            if (TERMINAL_STATUSES.includes(status)) {
42	                return false;
43	            }
44	
45	            return POLL_INTERVAL_MS;
46	        },
47	    });
48	
49	    const shouldShowErrorGrid = (summaryQuery.data?.history?.failCount ?? 0) > 0;
50	    const errorQuery = useQuery({
51	        queryKey: ['import-errors', numericHistoryId, page, size, sort],
52	        queryFn: () => getErrorPage(numericHistoryId, page, size, sort),
53	        enabled: shouldShowErrorGrid,
54	    });
55	
56	    const summary = summaryQuery.data;
57	    const isRunning = summary?.history?.status === 'PENDING' || summary?.history?.status === 'RUNNING';
58	
59	    if (summaryQuery.isLoading) {
60	        return <div className='rounded-2xl border border-border bg-card p-8 text-sm text-muted-foreground'>불러오는 중...</div>;
61	    }
62	
63	    if (!summary) {
64	        return null;
65	    }
66	
67	    return (
68	        <div className='space-y-6'>
69	            <h1 className='sr-only'>데이터 가져오기 상세</h1>
70	            <DetailHero
71	                eyebrow='데이터 가져오기'
72	                title={`가져오기 상세 #${summary.history.id}`}
73	                description={`${summary.history.fileName} 업로드 결과를 확인합니다.`}
74	                chips={[
75	                    { label: '상태', value: summary.history.status, tone: isRunning ? 'warning' : 'accent' },
76	                    { label: '유형', value: summary.history.type || '-' },
77	                    {
78	                        label: '실패',
79	                        value: `${summary.history.failCount ?? 0}건`,
80	                        tone: (summary.history.failCount ?? 0) > 0 ? 'danger' : 'success',
81	                    },
82	                ]}
83	            />
84	
85	            {isRunning ? <div className='h-2 animate-pulse rounded-full bg-muted' /> : null}
86	
87	            <div className='grid gap-3 md:grid-cols-2 xl:grid-cols-4'>
88	                <DetailStat label='전체' value={`${summary.history.totalCount ?? 0}건`} />
89	                <DetailStat label='성공' value={`${summary.history.successCount ?? 0}건`} tone='success' />
90	                <DetailStat label='실패' value={`${summary.history.failCount ?? 0}건`} tone='danger' />
91	                <DetailStat label='중복' value={`${summary.history.duplicateCount ?? 0}건`} />
92	            </div>
93	
94	            <DetailSection title='파일 정보' description='업로드 요청과 처리 상태를 확인합니다.'>
95	                <DetailFields
96	                    items={[
97	                        { label: '파일명', value: summary.history.fileName },
98	                        { label: '크기', value: `${summary.history.fileSize} bytes` },
99	                        { label: '요청자', value: `${summary.history.requestedBy} (${summary.history.requestedIp})` },
100	                        { label: '요청 시간', value: summary.history.requestedAt },
101	                        { label: '시작 시간', value: summary.history.startedAt || '-' },
102	                        { label: '종료 시간', value: summary.history.endedAt || '-' },
103	                        {
104	                            label: '전체 / 성공 / 실패',
105	                            value: `${summary.history.totalCount} / ${summary.history.successCount} / ${summary.history.failCount}`,
106	                        },
107	                        {
108	                            label: '중복 / staging',
109	                            value: `${summary.history.duplicateCount} / ${summary.history.stagingCount}`,
110	                        },
111	                        { label: '오류 요약', value: summary.history.errorSummary || '-', fullWidth: true },
112	                    ]}
113	                />
114	            </DetailSection>
115	
116	            {shouldShowErrorGrid ? (
117	                <DetailSection title='오류 목록' description='행 단위 오류를 확인합니다.'>
118	                    <DataGrid
119	                        columns={errorColumns}
120	                        pageData={errorQuery.data ?? null}
121	                        onPageChange={({ page: nextPage, size: nextSize }) => {
122	                            setPage(nextPage);
123	                            setSize(nextSize);
124	                        }}
125	                        onSortChange={({ active, direction }) => {
126	                            if (!direction || (active !== 'rowNo' && active !== 'errorCode')) {
127	                                setSort('row_no,asc');
128	                                return;
129	                            }
130	
131	                            const mapped = active === 'rowNo' ? 'row_no' : 'error_code';
132	                            setSort(`${mapped},${direction}`);
133	                        }}
134	                        onRowClick={(row) => {
135	                            setSelectedRawRow(row.rawRow ?? '');
136	                            setDetailOpen(true);
137	                        }}
138	                    />
139	                </DetailSection>
140	            ) : null}
141	
142	            <DetailPanel
143	                position='right'
144	                title='원본 데이터'
145	                open={detailOpen}
146	                onOpenChange={(open) => {
147	                    setDetailOpen(open);
148	                    if (!open) {
149	                        setSelectedRawRow('');
150	                    }
151	                }}
152	            >
153	                <DetailSection title='원본 행' description='업로드된 CSV의 원본 행을 확인합니다.'>
154	                    <pre className='whitespace-pre-wrap break-all text-sm text-muted-foreground'>{selectedRawRow}</pre>
155	                </DetailSection>
156	            </DetailPanel>
157	        </div>
158	    );
159	};
160	
161	export const DetailPage = () => {
162	    const { historyId } = useParams();
163	    const isValidHistoryId = typeof historyId === 'string' && /^[1-9]\d*$/.test(historyId);
164	
165	    if (!isValidHistoryId) {
166	        return <Navigate to='/home' replace />;
167	    }
168	
169	    return <DetailPageContent historyId={historyId} />;
170	};
