197	                            className='flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm text-foreground'
198	                            value={filters.useYn}
199	                            onChange={(event) =>
200	                                setFilters((current) => ({ ...current, useYn: event.target.value }))
201	                            }
202	                        >
203	                            <option value=''>전체</option>
204	                            <option value='Y'>사용</option>
205	                            <option value='N'>미사용</option>
