213	                pageSizeOptions={[10, 20, 50, 100]}
214	                onPageChange={({ page, size }) => setRequest((current) => ({ ...current, page, size }))}
215	                renderItem={(domain) => (
216	                    <DomainCard key={domain.id} domain={domain} onClick={(d) => setSelectedId(d.id)} />
217	                )}
218	            />
219	
220	            <DomainDetailDialog
221	                domain={detailQuery.data ?? null}
222	                open={isDetailOpen}
223	                onOpenChange={(open) => {
224	                    if (!open) setSelectedId(null);
225	                }}
226	            />
227	        </div>
228	    );
229	};
