1	import '@testing-library/jest-dom/vitest';
2	import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
3	import { render, screen, waitFor } from '@testing-library/react';
4	import userEvent from '@testing-library/user-event';
5	import { MemoryRouter, Route, Routes } from 'react-router-dom';
6	import { UploadPage } from './UploadPage';
7	
8	vi.mock('./importApi', () => ({
9	    uploadCsv: vi.fn(),
10	    getSummary: vi.fn(),
11	    getErrorPage: vi.fn(),
12	}));
13	
14	function renderUploadPage() {
15	    const queryClient = new QueryClient({
16	        defaultOptions: {
17	            mutations: { retry: false, gcTime: 0 },
18	            queries: { retry: false, gcTime: 0 },
19	        },
20	    });
21	
22	    return render(
23	        <QueryClientProvider client={queryClient}>
24	            <MemoryRouter initialEntries={['/import']}>
25	                <Routes>
26	                    <Route path='/import' element={<UploadPage />} />
27	                    <Route path='/import/:historyId' element={<div>Import Detail</div>} />
28	                </Routes>
29	            </MemoryRouter>
30	        </QueryClientProvider>,
31	    );
32	}
33	
34	describe('UploadPage', () => {
35	    test('requires a file before submit', async () => {
36	        const user = userEvent.setup();
37	
38	        renderUploadPage();
39	        expect(screen.getByRole('heading', { level: 1, name: '데이터 가져오기 업로드' })).toBeInTheDocument();
40	        await user.click(screen.getByRole('button', { name: '업로드' }));
41	
42	        const alert = screen.getByRole('alert');
43	
44	        expect(alert).toBeVisible();
45	        expect(screen.getByRole('button', { name: '업로드' })).toHaveAttribute('aria-describedby', alert.id);
