import axios from 'axios';

export const axiosInstance = axios.create({
    baseURL: '/api/v1',
    timeout: 30000,
    withCredentials: true,
    headers: {
        'Content-Type': 'application/json',
    },
});

const AUTH_ERROR_CODE = 'AUTH_1002';
let unauthorizedHandler = null;

const isUnauthorized = (status, code) => status === 401 || code === AUTH_ERROR_CODE;

const expireServerSession = () => {
    void axios.post('/api/v1/auth/logout', null, { withCredentials: true }).catch(() => {});
};

export const setUnauthorizedHandler = (handler) => {
    unauthorizedHandler = handler;
};

const handleUnauthorized = () => {
    // Global auth contract: any 401/AUTH_1002 response clears the local session and asks the server to expire the cookie.
    expireServerSession();
    unauthorizedHandler?.();
};

axiosInstance.interceptors.response.use(
    (response) => response,
    (error) => {
        const status = error.response?.status;
        const code = error.response?.data?.code;

        if (isUnauthorized(status, code)) {
            handleUnauthorized();
        }

        return Promise.reject(error);
    }
);

/**
 * @template T
 * @param {{data?: {success?: boolean, data?: T, message?: string} | null} | null | undefined} response
 * @returns {T}
 */
export const unwrapResponse = (response) => {
    const data = response?.data;

    if (data === null || data === undefined) {
        throw new Error('요청 처리에 실패했습니다.');
    }

    const isSuccess = data.success === true;
    const hasPayload = data.data !== null && data.data !== undefined;

    if (!isSuccess || !hasPayload) {
        throw new Error(data.message ?? '요청 처리에 실패했습니다.');
    }

    return data.data;
};
